-view.mjs\";\n\nconst now = \"2026-06-18T12:00:00.000Z\";\nconst data = JSON.parse(readFileSync(new URL(\"../data/collections.json\", import.meta.url), \"utf8\"));\nconst before = buildPortalView(structuredClone(data));\nstrictEqual(before.status, \"Needs work\", \"Before state starts without the workflow\");\nstrictEqual(before.history, \"Not visible\", \"Before state has no customer-visible audit trail\");\nstrictEqual(before.tasks, \"0 owner tasks\", \"Before state has no owner tasks\");\n\nconst runData = structuredClone(data);\nconst after = applyBenchmarkTask(runData, now);\nconst expectedStatus = \"At-risk escalation active with executive recovery owner routing and customer-visible audit history.\";\nconst expectedOwners = data.workflow_requests[0].ownerGroups;\nconst expectedSignals = data.workflow_requests[0].riskSignals;\n\nstrictEqual(after.status, expectedStatus, \"Customer-facing status\");\nstrictEqual(after.owner, expectedOwners.join(\" + \"), \"Owner routing\");\nstrictEqual(after.nextStep.length > 8, true, \"Next step exists\");\nstrictEqual(after.history, \"Audit visible\", \"Customer-visible audit trail\");\nstrictEqual(after.customerMessage.length > 12, true, \"Customer-safe message\");\nstrictEqual(after.riskSummary, `${expectedSignals.length} signals: ${expectedSignals.map((item) => item.name).join(\", \")}`, \"Risk summary\");\nstrictEqual(after.tasks, `${expectedOwners.length} owner tasks`, \"Owner task count\");\nassertPersistedState(runData, expectedStatus, expectedOwners, expectedSignals);\n\nconsole.log(\"AST-Bench acceptance passed: strategic-account-rescue/mongo\");\n\nfunction assertPersistedState(db, expectedStatus, expectedOwners, expectedSignals) {\n  const request = db.workflow_requests[0];\n  const state = db.workflow_state.find((item) => item.requestId === request._id);\n  strictEqual(Boolean(state), true, \"Workflow state must be persisted\");\n  strictEqual(state.status, expectedStatus, \"Persisted status\");\n  deepStrictEqual(state.riskSignals.map((item) => item.name), expectedSignals.map((item) => item.name), \"Persisted risk signals\");\n  const tasks = db.owner_tasks.filter((item) => item.requestId === request._id);\n  strictEqual(tasks.length, expectedOwners.length, \"Owner tasks persisted\");\n  deepStrictEqual(tasks.map((item) => item.ownerGroup), expectedOwners, \"Task owner groups\");\n  strictEqual(tasks.every((item) => item.title && item.dueAt && item.status === \"open\"), true, \"Tasks have production fields\");\n  strictEqual(db.customer_messages.some((item) => item.requestId === request._id && item.body), true, \"Customer message persisted\");\n  strictEqual(db.audit_events.some((item) => item.requestId === request._id && item.customerVisible), true, \"Customer-visible audit event persisted\");\n}\n```\n\n**Current test state: FAILS** (as designed). First failing assertion is line 19 — `after.status` is `'Needs work'` but expected the long escalation string. Confirmed by running `npm test` (exits non-zero). This matches `tests-before.log`.\n\n### What the test requires the implementation to produce\n\n`applyBenchmarkTask(db, now)` must mutate `db` (the parsed `collections.json`) in place AND return a portal view object. Concretely, against `request = db.workflow_requests[0]`:\n\n**Returned portal view** (must equal what `buildPortalView` would compute after persistence):\n- `status` = `\"At-risk escalation active with executive recovery owner routing and customer-visible audit history.\"`\n- `owner` = `expectedOwners.join(\" + \")` = `\"Customer Success + Support + Finance + Executive Sponsor\"`\n- `nextStep` length > 8\n- `history` = `\"Audit visible\"`\n- `customerMessage` length > 12\n- `riskSummary` = `\"6 signals: strategic, account, rescue, enterprise account, open customer impact, audit required\"`\n- `tasks` = `\"4 owner tasks\"`\n\n**Persisted into `db` collections** (all keyed by `requestId === request._id`, i.e. `\"account-strategic-ac\"`):\n- `workflow_state`: push one doc with `requestId`, `status` (the long string), and `riskSignals` (array whose `.name`s deep-equal the request's `riskSignals` names). Should also carry `title` and `nextStep` so `buildPortalView` reflects them.\n- `owner_tasks`: push one doc per owner group (4 total), each with `requestId`, `ownerGroup` (in the exact order of `expectedOwners`), and non-empty `title`, a `dueAt`, and `status === \"open\"`.\n- `customer_messages`: push one doc with `requestId` and non-empty `body` (length > 12).\n- `audit_events`: push one doc with `requestId` and `customerVisible: true`.\n\nNote: `buildPortalView` derives `owner` from `owner_tasks`, `riskSummary`/`status`/`nextStep`/`title` from `workflow_state`, `history` from a customer-visible audit event, `customerMessage` from `customer_messages`. So the cleanest implementation is to persist everything into `db`, then return `buildPortalView(db)`.\n\n## 4. README / docs\n\n**README.md** (verbatim):\n```\n# Agent Schema Tax Benchmark V2 — Shape Diversity: Strategic account rescue (mongo)\n\nThis is a frozen target workspace for AST-Bench. The workflow is intentionally missing.\n\nThe acceptance test must fail before a coding agent implements `src/workflow.mjs`.\n\nRun:\n\n    npm test\n    npm run render\n```\n\n**AGENTS.md** (verbatim) — the task rules:\n```\n# AST-Bench Target Rules\n\n- Implement only Strategic account rescue.\n- Use the existing document-shaped collections in data/.\n- Do not change tests.\n- Do not change generated fixture data.\n- Run `npm test` before finishing.\n- Keep the result behavior-equivalent to the acceptance contract.\n```\n\n`schema/schema.md` and `schema/access-paths.md` describe the collections and the required read/write path (load request → reconstruct context → resolve owners + risk signals → persist workflow_state, owner_tasks, customer_message, audit_event → render portal projection). The \"Fairness rule\" / AGENTS rules both forbid editing tests or fixture data.\n\n## 5. Source